'	"DEPARTMENT" VARCHAR2(4000) NOT NULL ENABLE, ',
'	 PRIMARY KEY ("DEPARTMENT_ID")',
'  USING INDEX  ENABLE',
'   ) ;',
'',
'CREATE TABLE "EMP_L" ',
'   (	"E_ID" NUMBER GENERATED BY DEFAULT AS IDENTITY MINVALUE 1 MAXVALUE 9999999999999999999999999999 INCREMENT BY 1 START WITH 1 CACHE 20 NOORDER  NOCYCLE  NOKEEP  NOT NULL ENABLE, ',
'	"E_NAME" VARCHAR2(20), ',
'	"DEPARTMENT_ID" NUMBER, ',
