'	"DISPLAY_ORDER" NUMBER NOT NULL ENABLE, ',
'	"CREATED" TIMESTAMP (6) WITH TIME ZONE NOT NULL ENABLE, ',
'	"CREATED_BY" VARCHAR2(255) NOT NULL ENABLE, ',
