'CREATE OR REPLACE FORCE EDITIONABLE VIEW "EBA_DEMO_SEARCH_CUST_ORD_PRD" ("ORDER_ID", "ORDER_STATUS", "ORDER_DATETIME", "CUSTOMER_ID", "EMAIL_ADDRESS", "FULL_NAME", "ORDER_TOTAL", "ITEMS") AS ',
'  select o.order_id,',
'      o.order_status,',
'      o.order_datetime,',
'      c.customer_id,',
'      c.email_address,',
'      c.full_name,',
'      sum ( oi.quantity * oi.unit_price ) order_total,',
'      listagg (p.product_name, '', '' on overflow truncate ''...'' with count)   ',
'         within group ( order by oi.line_item_id ) items  ',
'from eba_demo_search_orders o  ',
'join eba_demo_search_order_items oi ',
'  on o.order_id = oi.order_id  ',
'join eba_demo_search_customers c',
'  on o.customer_id = c.customer_id  ',
'join eba_demo_search_products p',
'  on oi.product_id = p.product_id',
'group by o.order_id,',
'        o.order_datetime,',
'        o.order_status,',
'        c.customer_id,',
'        c.email_address,',
'        c.full_name',
';',
'',
'CREATE OR REPLACE FORCE EDITIONABLE VIEW "EBA_DEMO_SEARCH_PRD_ORDERS" ("PRODUCT_NAME", "ORDER_STATUS", "TOTAL_SALES", "ORDER_COUNT") AS ',
'  select p.product_name,',
'       o.order_status,',
'       sum ( oi.quantity * oi.unit_price ) total_sales,',
'       count (*) order_count ',
'from eba_demo_search_orders o  ',
'join eba_demo_search_order_items oi ',
'  on o.order_id = oi.order_id  ',
'join eba_demo_search_customers c',
'  on o.customer_id = c.customer_id  ',
'join eba_demo_search_products p',
'  on oi.product_id = p.product_id',
'group by p.product_name  ',
',        o.order_status',
';',
'',
'CREATE OR REPLACE FORCE EDITIONABLE VIEW "EBA_DEMO_SEARCH_PRD_REVIEWS" ("PRODUCT_NAME", "RATING", "AVG_RATING", "REVIEW") AS ',
'  select p.product_name,',
'       r.rating,',
'       round (avg (r.rating) over (partition by product_name), 2) avg_rating,',
'       r.review',
'from eba_demo_search_products p,',
'    json_table  ',
'       (p.product_details, ''$.reviews[*]''  ',
'        columns (',
'            rating number path ''$.rating'',',
'            review varchar2(4000) path ''$.review'')  ',
'       ) r',
';',
'',
'CREATE OR REPLACE FORCE EDITIONABLE VIEW "EBA_DEMO_SEARCH_STR_ORDERS" ("TOTAL", "STORE_NAME", "ADDRESS", "LATITUDE", "LONGITUDE", "ORDER_STATUS", "ORDER_COUNT", "TOTAL_SALES") AS ',
'  select case  ',
'         grouping_id ( store_name, order_status )  ',
'           when 1 then ''STORE TOTAL''  ',
'           when 2 then ''STATUS TOTAL''  ',
'           when 3 then ''GRAND TOTAL''  ',
'       end total,',
'	         s.store_name,',
'	         coalesce ( s.web_address, s.physical_address ) address,',
'	         s.latitude,',
'	         s.longitude,',
'	         o.order_status,',
'	         count ( distinct o.order_id ) order_count,',
'	         sum ( oi.quantity * oi.unit_price ) total_sales  ',
'from eba_demo_search_stores s  ',
'join eba_demo_search_orders o ',
'  on s.store_id = o.store_id ',
'join eba_demo_search_order_items oi ',
'  on o.order_id = oi.order_id ',
'group by grouping sets (  (s.store_name, coalesce(s.web_address,s.physical_address), s.latitude, s.longitude) ,',
'							 (s.store_name, coalesce(s.web_address,s.physical_address), s.latitude, s.longitude, o.order_status),',
'							  o.order_status ,',
'							 ()  ',
'                       )',
';',
'',
'CREATE OR REPLACE FORCE EDITIONABLE VIEW "EBA_DEMO_SEARCH_STR_ORD_STAT" ("STORE_NAME", "ADDRESS", "LATITUDE", "LONGITUDE", "ORDER_STATUS", "ORDER_COUNT", "TOTAL_SALES") AS ',
'  select s.store_name,',
'        coalesce ( s.web_address, s.physical_address ) address,',
'        s.latitude,',
'        s.longitude,',
'        o.order_status,',
'        count ( distinct o.order_id ) order_count,',
'        sum ( oi.quantity * oi.unit_price ) total_sales ',
'from eba_demo_search_stores s',
'join eba_demo_search_orders o ',
'  on s.store_id = o.store_id',
'join eba_demo_search_order_items oi ',
'  on o.order_id = oi.order_id',
'group by  s.store_name, coalesce ( s.web_address, s.physical_address ), s.latitude, s.longitude, o.order_status',
';',
'',
'CREATE OR REPLACE FORCE EDITIONABLE VIEW "EBA_DEMO_TREE_DEF_ST_CODES" ("PCT_COMPLETE", "STATUS_NAME") AS ',
'  select 0   pct_complete, wwv_flow_lang.system_message(''NOT_STARTED'')                  status_name from dual union all',
'select 10  pct_complete, wwv_flow_lang.system_message(''UNDER_CONSIDERATION'')          status_name from dual union all',
'select 20  pct_complete, wwv_flow_lang.system_message(''APPROVED'')                     status_name from dual union all',
'select 30  pct_complete, wwv_flow_lang.system_message(''ASSIGNED'')                     status_name from dual union all',
'select 40  pct_complete, wwv_flow_lang.system_message(''WORK_INITIATED'')               status_name from dual union all',
'select 50  pct_complete, wwv_flow_lang.system_message(''WORK_PROGRESSING'')             status_name from dual union all',
'select 60  pct_complete, wwv_flow_lang.system_message(''SIGNIFICANT_PROGRESS'')         status_name from dual union all',
'select 70  pct_complete, wwv_flow_lang.system_message(''DEMONSTRABLE'')                 status_name from dual union all',
'select 80  pct_complete, wwv_flow_lang.system_message(''FUNCTIONALLY_COMPLETE'')        status_name from dual union all',
'select 90  pct_complete, wwv_flow_lang.system_message(''INTEGRATION_COMPLETE'')         status_name from dual union all',
'select 100 pct_complete, wwv_flow_lang.system_message(''COMPLETE'')                     status_name from dual',
';',
'',
'CREATE OR REPLACE FORCE EDITIONABLE VIEW "VIEW_CARD" ("NAME", "DEPARTMENT_ID") AS ',
'  select DEPARTMENT.NAME as NAME,',
'    DEPARTMENT_LOOKUP.DEPARTMENT_ID as DEPARTMENT_ID ',
' from DEPARTMENT_LOOKUP DEPARTMENT_LOOKUP,',
'    DEPARTMENT DEPARTMENT ',
' where DEPARTMENT.NAME=DEPARTMENT_LOOKUP.DEPARTMENT_ID',
'    and DEPARTMENT.ID=DEPARTMENT_LOOKUP.DEPARTMENT',
';',
'',
'CREATE OR REPLACE FORCE EDITIONABLE VIEW "VIEW_REBORT" ("PAGE_NO", "CATEGORY", "NAME_SHELF", "BOOK_NAME") AS ',
'  select BOOK.PAGE_NO as PAGE_NO,',
'    BOOK.CATEGORY as CATEGORY,',
'    SHELF.NAME_SHELF as NAME_SHELF,',
'    BOOK.BOOK_NAME as BOOK_NAME ',
' from SHELF SHELF,',
'    BOOK BOOK,',
'    BOOK_SHELF BOOK_SHELF ',
' where BOOK.ISBN=BOOK_SHELF.ISBN',
'    and BOOK_SHELF.SHELF_ID=SHELF.ID_SHELF',
';',
'',
''))
);
